import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { usePerCardRendererBoardCardChange, usePerCardRendererBoardLoadMore } from "./useCardChange";
import type { KanbanCardData } from "./types";

/**
 * Per-Card Renderer
 * card.render — overrides for individual cards
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 */
export default function PerCardRendererBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const handleCardChange = usePerCardRendererBoardCardChange();
  const handleLoadMore = usePerCardRendererBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={boardConfig}
        cards={cards}
        onCardsChange={setCards}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

import type { KanbanBuilderConfig } from "./types";

/** Static configuration. All fields are typed and validated. */
export const boardConfig: KanbanBuilderConfig = {
  "title": "Per-Card Renderer",
  "subtitle": "card.render — overrides for individual cards",
  "layout": "board",
  "columns": [
    {
      "id": "todo",
      "title": "To Do",
      "color": "amber"
    },
    {
      "id": "doing",
      "title": "Doing",
      "color": "blue"
    },
    {
      "id": "done",
      "title": "Done",
      "color": "emerald"
    }
  ],
  "visibleFields": [
    "priority",
    "assignee"
  ],
  "enableDnd": true,
  "enableAddCard": true,
  "enableWipLimits": false,
  "showColumnTotals": true,
  "compactCards": false
};

import type { KanbanCardData } from "./types";
import { cardRenderers } from "./renderers";
import { attachCardRenderers } from "../../components/kanban/attachRenderers";

/**
 * Per-card renderers live in ./renderers.tsx. `attachCardRenderers` wires
 * them onto each card's `render` field in a single O(n) pass.
 *
 * Resolution order at render time:
 *   card.render   ->   config.renderCard   ->   built-in <KanbanCard />
 */
const rawCards: KanbanCardData[] = [
  {
    "id": "f1",
    "columnId": "todo",
    "title": "Launch landing page redesign",
    "priority": "high",
    "assignee": "JD"
  },
  {
    "id": "f2",
    "columnId": "todo",
    "title": "Audit analytics events",
    "priority": "low"
  },
  {
    "id": "f3",
    "columnId": "doing",
    "title": "API rate-limit middleware",
    "priority": "medium",
    "assignee": "MR"
  },
  {
    "id": "f4",
    "columnId": "doing",
    "title": "Marketing site rebuild",
    "priority": "high",
    "assignee": "TK"
  },
  {
    "id": "f5",
    "columnId": "done",
    "title": "Migrate to React 18",
    "priority": "medium"
  }
];

export const initialCards: KanbanCardData[] = attachCardRenderers(rawCards, cardRenderers);

import { useCallback } from "react";
import type { KanbanCardData } from "./types";

/**
 * Called whenever a card is dropped into a new position via DnD.
 * Replace the body with your real backend call (e.g. fetch PATCH).
 */
export function usePerCardRendererBoardCardChange() {
  return useCallback((event: {
    card: KanbanCardData;
    fromColumnId: string;
    toColumnId: string;
    fromIndex: number;
    toIndex: number;
    cards: KanbanCardData[];
  }) => {
    console.log("[kanban] card moved:", event);
  }, []);
}

export function usePerCardRendererBoardLoadMore() {
  return useCallback(async (event: { columnId: string; cursor?: string }) => {
    console.log("[kanban] load more:", event);
  }, []);
}

/**
 * Re-export of the kanban engine types — imported by the generated component
 * so callers don't need to dig into the engine internals.
 */
export type {
  KanbanBuilderConfig,
  KanbanCardData,
  KanbanColumnConfig,
  KanbanCardField,
} from "../../components/kanban/types";
